                <div class="flex-1">
                    <h1 class="text-3xl font-bold text-[#1b1b18] mb-4">Afspraak maken</h1>
                    <p class="text-lg text-[#706f6c] mb-8">Kom langs voor een professionele knipbeurt.</p>
                    <div class="bg-white dark:bg-[#161615] rounded-xl p-6 shadow-sm">
                        <form class="space-y-6">
                            <div>
